#include <bits/stdc++.h>
using namespace std;
string s1,s2;
int p[26];
void dfs(int l,int r){
    if(l>r)
        return;
    int m=r+1;
    for(int i=l+1;i<=r;i++)
        if(p[s2[i]-'A']>p[s2[l]-'A']){
            m=i;
            break;
        }
    dfs(l+1,m-1);
    dfs(m,r);
    cout<<s2[l];
}
int main(){
    cin>>s1>>s2;
    s1=" "+s1;
    s2=" "+s2;
    for(int i=1;i<s1.size();i++)
        p[s1[i]-'A']=i;
    dfs(1,s2.size()-1);
    return 0;
}
